--
-- Name: find_places_by_mood_optimized(integer); Type: FUNCTION; Schema: public; Owner: apollinaria
--

CREATE FUNCTION public.find_places_by_mood_optimized(mood_id_param integer) RETURNS TABLE(place_id integer, title character varying, slug character varying, categories jsonb, match_score numeric, match_type text)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
        WITH RECURSIVE negative_matches AS (
            -- ?????????????? ???????????????? ?????????????????????????? ???????????????? ???????? ?? ??????????????????
            SELECT DISTINCT p.id
            FROM places p
            WHERE EXISTS (
                SELECT 1
                FROM jsonb_array_elements_text(p.categories) AS cat_slug
                         INNER JOIN mood_keywords mk ON
                    mk.categories_api_slug = cat_slug
                        AND mk.mood_id = mood_id_param
                        AND mk.is_negative = true
                WHERE (mk.search_in_title AND p.title ILIKE '%' || mk.keyword || '%')
                   OR (mk.search_in_description AND COALESCE(p.description, '') ILIKE '%' || mk.keyword || '%')
            )
              AND NOT p.is_closed
        ),
                       primary_places AS (
                           -- ???????????????????????????????? ???????????? ?????? ???????????????? ??????????????????
                           SELECT
                               p.id,
                               p.title,
                               p.slug,
                               p.categories,
                               (
                                   SELECT SUM(pcm.confidence)
                                   FROM jsonb_array_elements_text(p.categories) AS cat_slug
                                            INNER JOIN primary_category_moods pcm ON
                                       pcm.categories_api_slug = cat_slug
                                           AND pcm.mood_id = mood_id_param
                               ) as score,
                               'PRIMARY' as match_type
                           FROM places p
                           WHERE NOT p.is_closed
                             AND EXISTS (
                               SELECT 1
                               FROM jsonb_array_elements_text(p.categories) AS cat_slug
                                        INNER JOIN primary_category_moods pcm ON
                                   pcm.categories_api_slug = cat_slug
                                       AND pcm.mood_id = mood_id_param
                           )
                       ),
                       secondary_places AS (
                           -- ???????????????????????????????? ???????????? ?????? ?????????????????? ??????????????????
                           SELECT DISTINCT ON (p.id)
                               p.id,
                               p.title,
                               p.slug,
                               p.categories,
                               (
                                   SELECT SUM(scm.confidence)
                                   FROM jsonb_array_elements_text(p.categories) AS cat_slug
                                            INNER JOIN secondary_category_moods scm ON
                                       scm.categories_api_slug = cat_slug
                                           AND scm.mood_id = mood_id_param
                                   WHERE EXISTS (
                                       SELECT 1
                                       FROM mood_keywords mk
                                       WHERE mk.mood_id = mood_id_param
                                         AND mk.categories_api_slug = cat_slug
                                         AND mk.is_negative = false
                                         AND (
                                           (mk.search_in_title AND p.title ILIKE '%' || mk.keyword || '%')
                                               OR (mk.search_in_description AND COALESCE(p.description, '') ILIKE '%' || mk.keyword || '%')
                                           )
                                   )
                               ) as score,
                               'SECONDARY' as match_type
                           FROM places p
                           WHERE NOT p.is_closed
                             AND NOT EXISTS (
                               SELECT 1 FROM primary_places pp WHERE pp.id = p.id
                           )
                             AND EXISTS (
                               SELECT 1
                               FROM jsonb_array_elements_text(p.categories) AS cat_slug
                                        INNER JOIN secondary_category_moods scm ON
                                   scm.categories_api_slug = cat_slug
                                       AND scm.mood_id = mood_id_param
                                        INNER JOIN mood_keywords mk ON
                                   mk.mood_id = mood_id_param
                                       AND mk.categories_api_slug = cat_slug
                                       AND mk.is_negative = false
                               WHERE (mk.search_in_title AND p.title ILIKE '%' || mk.keyword || '%')
                                  OR (mk.search_in_description AND COALESCE(p.description, '') ILIKE '%' || mk.keyword || '%')
                           )
                       ),
                       combined_results AS (
                           SELECT * FROM primary_places
                           WHERE score IS NOT NULL
                           UNION ALL
                           SELECT * FROM secondary_places
                           WHERE score IS NOT NULL
                       )
        SELECT
            cr.id,
            cr.title,
            cr.slug,
            cr.categories,
            cr.score,
            cr.match_type
        FROM combined_results cr
        WHERE cr.id NOT IN (SELECT id FROM negative_matches)
        ORDER BY
            CASE WHEN cr.match_type = 'PRIMARY' THEN 1 ELSE 2 END,
            cr.score DESC;
END;
$$;


