6a52f8fbafbb6163a731089f0ab.jpg" src="//media.kudago.com/thumbs/xl/images/rich_editor/ef/8a/ef8a46a52f8fbafbb6163a731089f0ab.jpg"/></div><div class="contentSliderList-item post-big-preview-slide swiper-slide"><img alt="" class="contentImage-image contentImage-slider-image post-preview-image post-big-preview-image swiper-lazy" data-full="//media.kudago.com/images/rich_editor/b0/45/b045c88105a57ee8febb1fd4d85c09bc.jpg" src="//media.kudago.com/thumbs/xl/images/rich_editor/b0/45/b045c88105a57ee8febb1fd4d85c09bc.jpg"/></div><div class="contentSliderList-item post-big-preview-slide swiper-slide"><img alt="" class="contentImage-image contentImage-slider-image post-preview-image post-big-preview-image swiper-lazy" data-full="//media.kudago.com/images/rich_editor/69/e8/69e8825678e30de9ff41f777c5e8c1a6.jpg" src="//media.kudago.com/thumbs/xl/images/rich_editor/69/e8/69e8825678e30de9ff41f777c5e8c1a6.jpg"/></div><div class="contentSliderList-item post-big-preview-slide swiper-slide"><img alt="" class="contentImage-image contentImage-slider-image post-preview-image post-big-preview-image swiper-lazy" data-full="//media.kudago.com/images/rich_editor/92/84/9284582f3b245ea40e17bc920c87a5fe.jpg" src="//media.kudago.com/thumbs/xl/images/rich_editor/92/84/9284582f3b245ea40e17bc920c87a5fe.jpg"/></div></div><div class="contentSlider-pagination post-preview-pagination"></div><div class="contentSlider-navigation"><div class="swiper-button-prev"></div><div class="swiper-button-next"></div></div><div class="swiper-button-fullscreen"></div></div><p><em>*Подробные условия акции, её сроки и порядок проведения уточняйте у организаторов.</em> </p>	https://zuart.ru/	{"lat": 59.9114815999998, "lon": 30.311723700000012}	["Технологический Институт"]	f	[{"url": "https://media.kudago.com/images/place/0a/71/0a7131901e4680dd841827da2efe1e10.jpg", "source": "kudago", "is_main": true}, {"url": "https://media.kudago.com/images/place/eb/d7/ebd7b3877d87125825dd5bb9badb4dc2.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/18/90/189060ba292c092cf8e19e69b513aa9b.jpg", "source": "kudago", "is_main": false}]	https://media.kudago.com/images/place/0a/71/0a7131901e4680dd841827da2efe1e10.jpg	2025-10-20 19:19:04.896	2026-02-12 11:31:05.770087+00
430	18456	Зоопространство «ЗОО-ДЗЕН»	«ЗОО-ДЗЕН»	kontaktnyj-zoopark-lesnoe-posolstvo	["amusement"]	ул. Планерная, д. 59А (ТЦ «Монпансье», 3-й этаж)	ежедневно 10:00–21:00	+7 812 777-96-16	<p>Масштабная миссия, собственная конституция, продуманный свод законов — вот что отличает проект «ЗОО-ДЗЕН»  от его аналогов.</p>\n	<p>Обитатели — обаятельный кенгуру, любознательные еноты, уравновешенный дикобраз, весёлые братья-сурикаты, шустрые морские свинки, непоседы-кролики, красавица-лисица, деловая козочка, волнистые попугайчики, африканские ёжики, курицы и цыплята.</p>\n<p>За соблюдением правил в зоопространстве тщательно следят. Смотрители отвечают за то, чтобы животные не причиняли вреда посетителям, и наоборот.</p>\n<p>Для зоопространстве характерна открытая конструкция вольеров. Животных можно гладить и угощать разрешённым лакомством. Это позволяет гостям и пушистым обитателям обмениваться положительными эмоциями.</p>\n<p><strong>Стоимость посещения:</strong></p>\n<ul>\n<li>по будням — 350 рублей; </li>\n<li>по выходным и праздникам — 400 рублей; </li>\n<li>детям до трёх лет — бесплатно.</li>\n</ul>\n	https://vk.com/zooprostranstvospb	{"lat": 60.022171, "lon": 30.22294599999999}	["Комендантский Проспект, Пионерская, Старая Деревня"]	f	[{"url": "https://media.kudago.com/images/place/7c/7f/7c7f8a89fe90e4849083d964db18ee65.jpg", "source": "kudago", "is_main": true}, {"url": "https://media.kudago.com/images/place/95/b6/95b6900331d54213ff56531b6ec50e3a.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/aa/53/aa5375e866b79f1d61e5c74a6181af23.jpg", "source": "kudago", "is_main": false}]	https://media.kudago.com/images/place/7c/7f/7c7f8a89fe90e4849083d964db18ee65.jpg	2025-10-20 19:19:04.901	2026-02-12 11:31:05.770087+00
426	18509	Кинотеатр для двоих «Пандора»	Пандора	kinoteatr-pandora	["amusement", "sights", "cinema"]	наб. Обводного канала, д. 80	ежедневно 10:00–6:00	+7 812 602-51-81	<p>Хотите провести время с близким человеком в необычной обстановке и не отвлекаться на посторонних людей? В Петербурге расположились два кинотеатра, где влюблённые могут остаться наедине друг с другом и любимым фильмом.</p>\n	<p>В обычном кинотеатре практически невозможно найти места для влюблённых пар, а наличие большого количества людей вокруг не может не отвлекать. «Пандора» — частный кинотеатр, который прекрасно подходит для романтического свидания в сказочной атмосфере. Здесь не будет никого, кроме вас двоих. </p><p>К услугам гостей восемь залов, каждый из которых оформлен в индивидуальном и неповторимом стиле. Космос, море, сказочный лес, Индия, Голливуд — выбирайте наиболее понравившийся вариант и отправляйтесь в незабываемое кинопутешествие. Также вы можете поиграть в игровую приставку и попеть в караоке. </p><p>Широкий экран 2,5 на 5 метров и чёткая картинка позволят вам получить максимальное наслаждение от фильма или игры. Мягкие диваны, свечи, лепестки роз, шоколадное фондю, свежие фрукты, чай и спокойная музыка — команда кинотеатра позаботится об атмосфере и продумает каждую деталь.  </p><p>Помимо свидания, здесь можно провести яркий праздник, например, годовщину или день рождения, а также девичник в тесной компании без посторонних людей. В «Пандоре» есть возможность устроить тематическую вечеринку и сделать сюрприз невесте, а администратор поможет в организации мероприятия, украшения зала и в подборе музыкантов и фотографов. </p>		{"lat": 59.90953999999997, "lon": 30.32486900000001}	["Фрунзенская (временно закрыта)"]	f	[]	\N	2025-10-20 19:19:04.9	2026-02-12 11:31:05.770087+00
677	5044	Памятник Василию Корчмину	Памятник Василию Корчмину	pamyatnik-vasiliyu	["attractions"]	7-я линия В. О., д. 34			<p>Это памятник реальному человеку, сыгравшему немаловажную роль в истории Санкт-Петербурга.</p>\n	<p>Бомбардирский поручик Василий Корчмин командовал батареей, защищавшей город во время строительства Петропавловской крепости. Она базировалась на стрелке Васильевского острова, и Пётр I, отправляя приказы, подписывал их просто «Василию, на остров». Так остров получил своё название.</p>\n<p>Памятник этому персонажу появился здесь недавно, в 2001 году. Это работа дипломанта Академии художеств, который выиграл городской конкурс на создание проекта памятника.</p>\n		{"lat": 59.9411106462996, "lon": 30.28061746263398}	["Василеостровская"]	f	[{"url": "https://media.kudago.com/images/place/4f/63/4f6397512d9ed03e16abee2e363ede28.jpg", "source": "kudago", "is_main": true}]	https://media.kudago.com/images/place/4f/63/4f6397512d9ed03e16abee2e363ede28.jpg	2025-10-20 19:19:04.975	2026-02-12 11:31:05.770087+00
437	33347	Развлекательный центр X-House	X-House	attraktsion-x-house-33347	["amusement", "questroom"]	просп. Лахтинский, д. 85, лит. В	ежедневно 11:00–22:00	+7 932 715-18-34	<p>Современное игровое пространство подходит для отдыха всей семьёй, с друзьями или в одиночку, а также для проведения корпоративов и праздников. Много места и доступные цены — то, что нужно для больших компаний!</p>	<p>В центре X-House можно погрузиться в виртуальные миры уникальных VR-игр и сразиться в лазертаг на огромной площадке, приспособленной для чемпионатов: игровое пространство площадью почти 750 квадратных метров вмещает более 30 игроков одновременно. Высококлассное оборудование превратит игру в захватывающее приключение.</p><p>Играть в VR можно в команде, а можно одному. Игры на базе HTC VIVE PRO размещены в просторных залах площадью до 150 квадратных метров. Любителям пряток стоит опробовать экшн-игру в реальности «Прятки Lite»: испытайте себя, удастся ли вам остаться незамеченным?\n</p><p>После игр можно отдохнуть в космической зоне, заказать закуски и напитки. </p>	https://vk.com/x__house	{"lat": 59.99343760000008, "lon": 30.14339789999968}	["Беговая"]	f	[{"url": "https://media.kudago.com/images/place/1d/68/1d68e04dc77c8e79fb724ddd5b9e87a8.jpg", "source": "kudago", "is_main": true}]	https://media.kudago.com/images/place/1d/68/1d68e04dc77c8e79fb724ddd5b9e87a8.jpg	2025-10-20 19:19:04.903	2026-02-12 11:31:05.770087+00
440	34048	Киберпространство TopTab	topTab	attraktsion-toptab	["amusement"]	ул. Кораблестроителей, д. 30	ежедневно весь день	+7 911 785-11-64	<p>Крутое место на карте Петербурга, которое придётся по вкусу не только искушённым геймерам, но и тем, кто впервые решил окунуться в мир удивительных видеоигр. </p>	<p>TopTab — это не просто клуб, а целая киберспортивная арена. Здесь установлено 73 мощных компьютера на базе процессоров IntelCore, Nvidia RTX с профессиональными игровыми девайсами Logitech/HyperX и мониторами Alienware 360Гц, Benq 144/240Гц. </p><p>Для удобства любителей видеоигр залы оборудованы креслами VMM. В TopTab размещена киберсцена для проведения больших турниров. Также для небольших компаний предусмотрены LUXE- и VIP-комнаты, зона отдыха с PS5 на проекторе 150 дюймов и изображением в 4К-разрешении.</p><p>В TopTab можно не только совершенствовать свои навыки в области киберспорта, но и просто отдохнуть с друзьями и погрузиться в виртуальный мир.</p><p>Здесь есть своя кухня, где предлагают заказать бургер, шаверму, пасту и другие блюда: не придётся прерывать игру, чтобы подкрепиться!</p>	https://vk.me/toptabclub	{"lat": 59.95176326969148, "lon": 30.216446837050896}	["Приморская"]	f	[{"url": "https://media.kudago.com/images/place/03/7a/037abedccec683ffea960ec3c99237ec.jpg", "source": "kudago", "is_main": true}, {"url": "https://media.kudago.com/images/place/a3/c3/a3c3ddc9a602a9bb2dd4756b3881eaa2.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/67/62/6762cfe12ddc43b843311f2ceb83b652.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/0f/12/0f12ed1d4fc2a9b16294bcd04be06386.jpg", "source": "kudago", "is_main": false}]	https://media.kudago.com/images/place/03/7a/037abedccec683ffea960ec3c99237ec.jpg	2025-10-20 19:19:04.904	2026-02-12 11:31:05.770087+00
1020	1130	Ресторан О! Cuba	О! Cuba	o-cuba	["restaurants"]	ул. Рубинштейна д. 36	ежедневно 11:00–23:00	+7 911 022-40-25	<p>Ресторан О!Cuba — заведение с аутентичной карибско-кубинской обстановкой, самым широким в городе выбором сортов рома и атмосферой зажигательного латиноамериканского веселья. Прямо в зале ресторана стоит ретро-автомобиль любимой марки Фиделя Кастро.</p>\n	<p>Один из залов ресторана оформлен в стиле кубинского пляжного кафе с плетёной мебелью, обилием зелени и ярких солнечных красок. Второй представляет улочку старого Тринидада с вымощенной камнем мостовой, старинными ставнями на окнах, фигурными коваными решетками. Здесь располагается главная достопримечательность ресторана — раритетный автомобиль-лимузин марки «Бьюик» 1956 года выпуска, любимая модель легендарного главы солнечного острова Фиделя Кастро. Третий зал создан в стиле уютного уединённого кубинского дворика, где можно приятно провести сиесту с бокалом ледяного коктейля в оживленной беседе. Стены залов украшены кубинскими флагами, портретами и плакатами с изображением Кастро, фотографиями видов Гаваны разных лет в старинных деревянных рамках.</p>\n<p>Меню в ресторане О! Cuba тоже типично карибское. Кроме национальных кубинских блюд, здесь можно попробовать популярные кушанья всего Карибского региона и Мексики — эскавече с тигровыми креветками и авокадо, севиче с лососем и кукурузными початками в остром маринаде, кукурузные чипсы, мясные копчёности хамон, ломо и эмбутидос, национальные супы потахильо и гаспачо, блюда из рыбы разных сортов и морепродуктов. Завершить трапезу можно необычными десертами — например, шоколадной сигарой, как у самого Че. Созданием всего этого тропического великолепия заведение обязано шеф-повару Даловару Хоссаину.</p>\n<p>Но особенной популярностью пользуются в этом заведении напитки. Знаменитый коктейль «Мохито» в О! Cuba готовится по особому национальному рецепту, да и остальные известные карибские миксы — Mulata, Comandante, President — отличаются особенным, истинно кубинским вкусом. А рома, без которого невозможно представить себе латиноамериканскую романтику, здесь рекордное количество сортов, такого изобилия марок этого напитка нельзя найти больше нигде в Петербурге.</p>\n<p>Неповторимую карибскую атмосферу дополняет живая испанская и кубинская музыка, которая звучит здесь по вечерам пять дней в неделю.</p>\n	https://o-cuba.ru/	{"lat": 59.93198599999999, "lon": 30.34544999999999}	["Гостиный двор, Маяковская"]	f	[{"url": "https://media.kudago.com/images/place/f1/54/f1543c2a71aebea04bf792d43b617cfd.jpg", "source": "kudago", "is_main": true}]	https://media.kudago.com/images/place/f1/54/f1543c2a71aebea04bf792d43b617cfd.jpg	2025-10-20 19:19:05.074	2026-02-12 11:31:05.770087+00
446	30473	Студия актёрской импровизации «Точка Импро»	Точка Импро	kurs-tochka-impr	["amusement", "education-centers"]	ул. Мира, д. 3, бизнес-центр «Троицкий»	пн–пт 10:00–22:00, сб, вс 11:00–20:00	+7 800 201-36-74	<p>Создать историю без единой строчки текста и исполнить её на сцене подвластно каждому. Студия «Точка Импро» приглашает в увлекательный мир мгновенного театра, где можно классно провести время, снять напряжение и стать увереннее в себе.</p>	<p>Студия  актёрской  импровизации «Точка Импро» проводит увлекательные занятия по импровизации в позитивной атмосфере. Участники занятий знакомятся, много смеются и не боятся ошибаться. Здесь можно завести друзей и отдохнуть от будничной рутины, а также стать увереннее в себе и избавиться от страха публичных выступлений. После занятий по импровизации уже не страшно попадать в неловкие ситуации, потому что всегда можно сымпровизировать и с юмором обыграть любой момент. Первый пробный урок — бесплатный.</p><p>Преподаватели студии — опытные импровизаторы, участвующие в фестивалях и таких проектах, как «Импровизация. Команды». Каждый курс завершается полноценным выступлением  перед зрителями. Как правило, огромное удовольствие от этого получают все, даже те, кто выходит на сцену в первый раз. </p><p>«Точка Импро» — это большой клуб единомышленников, здесь можно встретить людей самых разных возрастов и профессий. Здесь проводятся не только занятия, но также фестивали и выездные мероприятия. </p><div class="contentVideo"><div class="contentVideo-outer"></div></div>	https://vk.com/tochkaimpro	{"lat": 59.9590849999999, "lon": 30.31376820000006}	["Горьковская"]	f	[{"url": "https://media.kudago.com/images/place/84/b5/84b583696513665ed547f85fbbf26ff5.jpg", "source": "kudago", "is_main": true}, {"url": "https://media.kudago.com/images/place/6a/e0/6ae0f628901e1650f096122e9dc068e0.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/6d/be/6dbe6d61e23c2a0da1c88462e32ff250.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/b3/73/b3732c0798ab354c9da48485df309582.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/79/c8/79c89c231fbb510336e24d9ecdf9800d.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/93/ef/93ef71fa325a7907a0dd8829e0a645b4.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/7c/75/7c75d90c95d6e3bd45d42e5381291b33.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/f4/a2/f4a22457772e0bedc084a06a3f190299.JPG", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/9c/a3/9ca3554bb4fc68e0bb01ed717112f79a.JPG", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/e7/13/e7130feee6283cb17b16de8072c15403.jpg", "source": "kudago", "is_main": false}]	https://media.kudago.com/images/place/84/b5/84b583696513665ed547f85fbbf26ff5.jpg	2025-10-20 19:19:04.905	2026-02-12 11:31:05.770087+00
447	5202	Санкт-Петербургская филармония джазовой музыки	санкт-Петербургская филармония джазовой музыки	filarmoniya-dzhazovoj-muzyki	["amusement", "art-space", "sights", "concert-hall"]	просп. Загородный, д. 27	касса: ежедневно 14:00–20:00	+7 812 764-85-65	<p>Это место притяжения ценителей джазовой музыки известно далеко за пределами Северной столицы. Сюда приезжают с концертами выдающиеся исполнители джаза со всего мира. При этом филармония является живым и открытым пространством для каждого слушателя.</p>\n	<p>Филармонию джазовой музыки, известную также как Jazz Philharmonic Hall, открыли в бывшем доходном доме в конце 1980-х по инициативе народного артиста Давида Голощёкина. За это время она прошла большой путь, превратившись в виднейшую джазовую площадку.</p><p>Сегодня концертные программы для взрослых и детей проходят в двух залах: Большом и Эллингтоновском. В первом также проводят вечера танцевального джаза. Кроме того, гостей здесь ждут в единственном в стране тематическом музее. Его экспонаты знакомят с развитием этого музыкального направления в городе.</p>	https://vk.com/jazz_hall	{"lat": 59.92403199999999, "lon": 30.33678999999999}	["Звенигородская, Пушкинская"]	f	[{"url": "https://media.kudago.com/images/place/e6/f2/e6f26b291e79adf8340e4650780c16e1.jpg", "source": "kudago", "is_main": true}]	https://media.kudago.com/images/place/e6/f2/e6f26b291e79adf8340e4650780c16e1.jpg	2025-10-20 19:19:04.906	2026-02-12 11:31:05.770087+00
686	5374	Граффити-брандмауэр на Маршала Новикова, 1	Граффити-брандмауэр на Маршала Новикова, 1	graffiti-brand	["attractions"]	просп. Маршала Новикова, д. 1			<p>Торцевая часть дома без окон с труднопроизносимым иностранным названием «брандмауэр» на проспекте Маршала Новикова украшена огромным граффити с множеством художественных элементов. Высота стены — 35 метров!</p>\n	<p>Это тот случай, когда граффити оказалось не вне закона, а наоборот — появилось с подачи властей в рамках проекта «Сто легальных стен». Рисунок создали в 2008 году участники фестиваля «Meeting of Styles», с тех пор он периодически подкрашивается.</p>\n<p>Расписывал стену не один человек, а сразу 10 художественных команд как из России, так и из Европы и США. Увы, но новых граффити-проектов власти района пока не намечают — по их словам, это требует соблюдения слишком многих формальных процедур и вложения немалых денежных средств.</p>\n		{"lat": 60.00887800000001, "lon": 30.26801500000001}	["Комендантский Проспект"]	f	[{"url": "https://media.kudago.com/images/place/af/6a/af6a9a4fe971017c0f198f775acc2620.jpg", "source": "kudago", "is_main": true}, {"url": "https://media.kudago.com/images/place/f9/f4/f9f4194c9807c801067cbcc05984304a.jpg", "source": "kudago", "is_main": false}]	https://media.kudago.com/images/place/af/6a/af6a9a4fe971017c0f198f775acc2620.jpg	2025-10-20 19:19:04.977	2026-02-12 11:31:05.770087+00
452	24181	Аэротруба Butterfly	Butterfly	aerotruba-butterfly	["amusement", "recreation"]	г. Зеленогорск, ш. Приморское, д. 536	пн–пт 11:00–21:00, сб, вс 10:00–21:00	+7 921 940-04-94	<p>Мечтаете научиться летать, но побаиваетесь прыгать с парашютом? В аэротрубе Butterfly можно испытать непередаваемое ощущение свободного полёта. Гравитация и порыв воздуха поднимут вас ввысь и заставят парить!</p>\n	<p>Полёты в аэротрубе — удивительная возможность испытать ощущение свободного падения. Потоки воздуха поднимают участников вверх. В этот момент гравитация перестаёт властвовать над телом, появляется непередаваемое чувство радости и лёгкости, а сознание захлёстывает настоящая буря ярких эмоций.</p>\n<p>Перед полётом посетителям выдают необходимую экипировку. Опытный инструктор проводит подготовку к полёту: показывает правильное положение тела, рассказывает, как летать, и отвечает на вопросы. Развлечение доступно даже для четырёхлетних детей. Кстати, здесь работает детская секция полётов, где ребята укрепляют мышцы, развивают собранность и координацию.</p>\n<p>Для всех желающих предусмотрены спортивные тренировки, во время которых учат управлять телом в воздушном потоке так, как это делают профессиональные парашютисты.</p>\n<p>Аэротруба Butterfly закрытого типа, а это значит, что там всегда тепло, и поэтому летать можно в любую погоду — надевайте экипировку, внимательно слушайте советы инструктора и наслаждайтесь полётом!</p>\n	https://vk.com/aero_butterfly	{"lat": 60.19086866165054, "lon": 29.70684516804508}	["Старая Деревня"]	f	[{"url": "https://media.kudago.com/images/place/da/69/da695ad68336607c2eb480b9037ae86b.jpg", "source": "kudago", "is_main": true}]	https://media.kudago.com/images/place/da/69/da695ad68336607c2eb480b9037ae86b.jpg	2025-10-20 19:19:04.908	2026-02-12 11:31:05.770087+00
436	3562	Парк семейного отдыха и экотуризма «Зубровник» в Токсово	«Зубровник» в Токсово	park--zubrovnik	["amusement"]	Ленинградская обл., пос. Токсово	ежедневно 10:00–18:00	+7 921 959-89-40, +7 921 954-90-66	<p><strong>Парк семейного отдыха и экотуризма «Зубровник»</strong> — удивительное место, где можно посмотреть на стадо зубробизонов, покататься на лошадях в конном клубе или взять напрокат квадроциклы для катания по Кавголовскому лесопарку.</p>\n	<p>Зубропитомник находится на территории лесопарковой зоны, в посёлке Токсово, который отличается чистотой воздуха и хорошей экологической обстановкой. Помимо зубров, здесь живут кролики, птицы, лошади, пони, козы, овцы и мускусные утки, которых дети могут покормить. Для знакомства с животными проводятся обзорные экскурсии.</p>\n<p>Занятия в конном клубе — одно из направлений парка семейного отдыха. Здесь проходит обучение верховой езде для детей и взрослых: за несколько занятий приобретаются основные навыки по управлению лошадью или пони. Для опытных ездоков предлагается обучение конкуру (соревнования по преодолению препятствий на лошадях). Ну а для желающих поправить здоровье есть иппотерапия (лечебная верховая езда) — ещё одно специализированное направление клуба.</p>\n<p>На территории зубровника есть также верёвочный городок для детей от 5 лет. А «Дом Времени» (Рыцарский Дом-музей) предлагает отправиться в прошлое: увидеть занимательные предметы старины и познакомиться с разными эпохами — от рыцарей Круглого стола до казаков и Наполеона Бонапарта.</p>\n<p>Для любителей активного отдыха парк предоставляет площадки для волейбола, футбола, а также оборудованную территорию для игры в пейнтбол и тир.</p>\n<p>Парк идеально подходит для организации детских и семейных праздников: тут есть увлекательные экскурсионные программы, координаторы предлагают различные сценарии для проведения Дней рождения и выпускных праздников. Есть возможность заказать программы с аниматорами по различным авторским сценариям.</p>\n<p>На территории парка также работает кафе и организована беседка с площадкой под барбекю.</p>\n<p>Вход бесплатный.</p>\n<object width="720" height="515"><param name="movie" value="//www.youtube.com/v/SOGZaCbiudo?version=3&hl=en_GB"></param><param name="allowFullScreen" value="true"></param><param name="allowscriptaccess" value="always"></param><embed src="//www.youtube.com/v/SOGZaCbiudo?version=3&hl=en_GB" type="application/x-shockwave-flash" width="720" height="515" allowscriptaccess="always" allowfullscreen="true"></embed></object>	http://zubrovnik.ru/	{"lat": 60.153723706895136, "lon": 30.461139674714484}	["Проспект Просвещения"]	f	[{"url": "https://media.kudago.com/images/place/6c/76/6c76a025f50f84b0fea851dbf71a95eb.jpg", "source": "kudago", "is_main": true}, {"url": "https://media.kudago.com/images/place/85/ef/85efa0fc3bd2471cd3d158ab658f3aff.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/9b/c9/9bc90f8c23799fc262d3e8ae6651adbf.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/fa/cc/facc046ff5b7c128ed92cf4982ad77d6.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/b1/d0/b1d0c0d555d470a31587a4dc05f1b3ff.jpg", "source": "kudago", "is_main": false}]	https://media.kudago.com/images/place/6c/76/6c76a025f50f84b0fea851dbf71a95eb.jpg	2025-10-20 19:19:04.903	2026-02-12 11:31:05.770087+00
476	1341	Парк «Новая Голландия»	Новая Голландия	art-prostranstvo-novaya-gollandiya2	["park", "art-space", "attractions", "sights", "recreation"]	наб. Адмиралтейского канала, д. 2	пн–чт 9:00–22:00, пт–вс 9:00–23:00	+7 812 245-20-35	<p>Новое пространство стало глотком свежего воздуха для Северной столицы. Книжный магазин, инсталляции, концертная площадка, лужайка летом, каток зимой и не только.</p>\n	<p>Пройдитесь по набережной Мойки от центра. Остров виден издалека — высокие кирпичные стены, фанерные окна, заросли у воды. Вход в «Новую Голландию» теперь открыт с двух сторон. Будьте готовы к тому, что охранники попросят показать содержимое сумок, а напитки и еду оставят дожидаться вас в специальных ячейках. Ноги, ступающие на территорию арт-пространства, обычно сами направляют своих владельцев вначале к фотобудке, потом к модным кафе, а напоследок просятся полежать на зелёной траве, если на дворе лето, или обуть коньки и выйти на каток зимой. </p><p>Небольшой экскурс: молва приписывает острову лагерно-арестантское предназначение, история же утверждает, что здесь конструировались и тестировались суда советского флота. Тюрьма тут всё-таки была. За свою форму она получила название «бутылка». Именно отсюда и пошло выражение «не лезь в бутылку». Впрочем, достоверно лишь то, что долгое время сильно разрушенные в годы Великой Отечественной войны постройки не использовались, не реставрировались и пустовали.</p><p>Сейчас же территорию острова действительно значительно преобразили. «Новая Голландия» стала огромным арт-объектом в центре Петербурга. А рядом с ней — дома с теми самыми питерскими крышами, которые показывают в фильмах.</p><p>Мероприятия, проводимые на острове, собирают, пожалуй, самую разнообразную аудиторию. То концерт, на который приходят любители потанцевать, то День библиотеки, куда стекаются книгочеи, то лекция для молодых родителей, то День астрономии или постановка современного балета. Бывают вечера и без мероприятий. В такие дни на острове играют в бадминтон или теннис, лежат на траве, сидят с ноутбуками (везде бесплатный Wi-Fi), читают книги.</p><p>«Новую Голландию» закрывали на реконструкцию и обещали вернуть жителям в 2018 году, но справились гораздо раньше: частично обновлённый парк открылся уже в августе 2016-го. Первые изменения коснулись «бутылки». В ней появились рестораны и кафе, книжный магазин, залы для занятия йогой и балетом.</p><p>Новых зданий в «Новой Голландии» решили не строить. Вместо этого закупили несколько сотен деревьев в европейских питомниках. Уже сейчас здесь можно пройтись по липовой аллее. В парке также регулярно появляются скульптуры, инсталляции и арт-объекты художников из разных уголков планеты.</p><p>Летом 2020 года в «Новой Голландии» открылась новая часть пространства вокруг отреставрированного «Дома 12». Теперь гости могут увидеть Садовую аллею — ещё одну достопримечательность зелёной зоны. Над разработкой проекта работала архитектурная компания West 8 при участии ландшафтного дизайнера Линды Берд. Здесь высадили 119 ирг Ламарка, 26 яблонь, гортензию, магонию, рябинник, иву, калину и многое другое.</p><p>А в 2022 году тут появилось «Сообщество» — городская гостиная для тех, кто любит проводить время на острове, место, где можно встретить интересных людей, поработать, послушать лекции, посмотреть кино и провести открытое мероприятие.</p><p>Вход на остров свободный.</p><div class="faq-wrapper" itemscope="" itemtype="https://schema.org/FAQPage"><div class="faq-title"><h3>Часто задаваемые вопросы</h3><div class="faq-block-toggle faq-block-toggle_close"></div></div><div class="faq-content faq-content_close"><div class="faq-content-item" itemprop="mainEntity" itemscope="" itemtype="https://schema.org/Question"><div class="faq-content-item-question" itemprop="name">Что такое Парк «Новая Голландия» и какие возможности он предлагает для посетителей?\n</div><div class="faq-content-item-answer" itemprop="acceptedAnswer" itemscope="" itemtype="https://schema.org/Answer"><div itemprop="text"><p>Парк «Новая Голландия» — это арт-пространство и культурный центр в Санкт-Петербурге, который предлагает посетителям множество возможностей. Здесь можно прогуляться по зелёным аллеям, отдохнуть на траве, насладиться инсталляциями и принимать участие в различных мероприятиях, таких как концерты, лекции и выставки. Парк также включает кафе, книжный магазин и пространства для активного отдыха, например, для йоги.</p></div></div></div><div class="faq-content-item" itemprop="mainEntity" itemscope="" itemtype="https://schema.org/Question"><div class="faq-content-item-question" itemprop="name">Каковы часы работы парка и есть ли входная плата?\n</div><div class="faq-content-item-answer" itemprop="acceptedAnswer" itemscope="" itemtype="https://schema.org/Answer"><div itemprop="text"><p>Парк «Новая Голландия» обычно открыт с понедельника по четверг с 09:00 до 22:00, а с пятницы по воскресенье — с 09:00 до 23:00. Вход на территорию парка бесплатный, что делает его доступным для всех желающих.</p></div></div></div><div class="faq-content-item" itemprop="mainEntity" itemscope="" itemtype="https://schema.org/Question"><div class="faq-content-item-question" itemprop="name">Какие мероприятия проводятся в парке «Новая Голландия»?\n</div><div class="faq-content-item-answer" itemprop="acceptedAnswer" itemscope="" itemtype="https://schema.org/Answer"><div itemprop="text"><p>В парке «Новая Голландия» проводятся разнообразные мероприятия, включая музыкальные концерты, кинопоказы, мастер-классы и лекции. Также в парке организуют спортивные активности и культурные фестивали, что делает его популярным местом для встреч и отдыха в Санкт-Петербурге.</p></div></div></div></div><div class="faq-hidden"></div></div>	https://vk.com/newhollandsp	{"lat": 59.92832, "lon": 30.29195499999999}	["Адмиралтейская"]	f	[{"url": "https://media.kudago.com/images/place/25/c8/25c88d23169c337cb8a5893830893f2e.jpg", "source": "kudago", "is_main": true}, {"url": "https://media.kudago.com/images/place/e4/b1/e4b10a4a078cebfd42ae94934986c6f7.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/88/5f/885f0e32f2fccb28a2f58eace2e43a33.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/5a/38/5a38cab7323554d00f84e5f36f470958.jpeg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/c8/7c/c87cd4edd9357cfdda583723f60f8abd.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/6c/04/6c04f264756eb00bdaf47c17384149a5.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/33/e3/33e324cd741606dfbf7ba3210775bd12.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/2a/6b/2a6b24501725cc23ba2df2a3e28ba8fb.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/63/4e/634ee8b2e164d117f7890ed2b4eb3fc9.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/6f/11/6f1127afdfc8c55a19557a898435702b.jpg", "source": "kudago", "is_main": false}]	https://media.kudago.com/images/place/25/c8/25c88d23169c337cb8a5893830893f2e.jpg	2025-10-20 19:19:04.916	2026-02-12 11:31:05.770087+00
460	28948	Антикафе «МечтаТут»	МечтаТут	antikafe-mechtatut	["anticafe"]	ул. Есенина, д. 1, корп. 1, пом. 87-Н	пн, вс 10:00–23:00, вт–сб 10:00–5:30	+7 911 755-64-78	<p>Душевные посиделки, настольные  игры, интересные знакомства, мастер-классы и кинопоказы — ещё одно место уюта, добра и хорошего настроения появилось в северной части Петербурга.</p>\n	<p>Новое антикафе «МечтаТут» вместимостью до 100 человек предлагает гостям светлое и комфортное пространство, где каждый найдёт занятие по душе. Формат антикафе уже полюбился жителям Петербурга за демократичные цены, скоростной wi-fi, возможность согреться чашкой горячего чая или кофе. А ещё здесь можно организовать свое мероприятие или отметить день рождения.</p>\n<p>В коллекции антикафе «МечтаТут» вы найдёте десятки популярных настольных игр разных жанров, приставки Xbox+kinect, Sony Playstation One, Dendi и Sega с любимыми компьютерными хитами.</p>\n<p>Для поклонников активных игр в антикафе предназначен отдельный зал с профессиональным теннисным столом и необходимым оборудованием. Устраивайте с друзьями захватывающие матчи! А если вы сможете обыграть звезду антикафе — администратора Soul — вас ждёт приятный подарок.</p>\n<p>Стоимость минуты составляет 3 рубля с человека, минимальный чек — 200 рублей, максимальный — 740 рублей (кроме тех, кто играет в Xbox). Также действуют специальные условия на бронирование столов, аренду залов и техники.</p>\n	https://vk.com/me4tatv	{"lat": 60.02817810000008, "lon": 30.32962679999962}	["Озерки"]	f	[{"url": "https://media.kudago.com/images/place/95/cf/95cf010f77a66a03b4fed4b693db83d7.jpg", "source": "kudago", "is_main": true}]	https://media.kudago.com/images/place/95/cf/95cf010f77a66a03b4fed4b693db83d7.jpg	2025-10-20 19:19:04.911	2026-02-12 11:31:05.770087+00
462	1713	Антикафе «12 комнат»	«12 комнат»	antikafe-12-komnat	["coworking", "anticafe"]	ул. Думская, д. 4.	ежедневно 10:00–6:00	+7 812 923-70-96	<p>Пространство для отдыха, общения или работы в центре Петербурга.</p>\n	<p>В антикафе на Думской комнат даже больше, чем дюжина, и каждая готова принять гостей. Пространство в 750 м²  с нестандартным дизайном  интригует — хочется непременно побывать во всех комнатах.</p><p>Изолированность комнат позволяет проводить мероприятия различного формата — от деловых встреч до неформальных вечеринок, от тренингов и семинаров до домашних концертов и празднования дней рождения. Одних привлекает кинозал, другие полюбили «Мафию», третьи — завсегдатаи разговорных клубов, четвёртые ценят коворкинг — здесь беспроводной интернет, розетки, удобные рабочие места. Подобное зонирование позволяет в антикафе собираться людям с разными вкусами — каждый по-своему проводит время и никто никому не мешает.</p><div class="contentImage"><div class="contentImage-inner"><img alt="" class="contentImage-image" data-full="//media.kudago.com/images/rich_editor/c3/1d/c31de187c3c5009bcafc3b5fba662ad8.jpg" src="//media.kudago.com/thumbs/xl/images/rich_editor/c3/1d/c31de187c3c5009bcafc3b5fba662ad8.jpg"/></div></div><h2>Тарифы и опции</h2><p>Еду можно приносить с собой, алкоголь под запретом. Для гостей трудятся профессиональные бариста, в меню — сорта кофе со всего земного шара с оригинальными наполнителями. Гостям предлагают не только классику кофе, но и авторские рецепты — черничный латте, латте с халвой, капучино с мёдом и корицей, какао и многое другое. Также гостей ждёт также большой выбор сортов китайского чая.</p><p>Стоимость пребывания демократична, средний чек редко превышает 250 рублей, а больше 900 не бывает никогда — счётчик останавливается. Для гостей действуют целых четыре тарифа: «Базовый», «Чайный», «Кофейный» и «Единый».</p><h2>Акции</h2><p>Для всех тарифов, кроме «Базового», действует акция «Суши-понедельник»: роллы и поке от профессионального сушиста по понедельникам с 12:00 до 20:00. Еда уже входит в оплату за время; минимальный счёт — 350 рублей, а максимальный для каждого тарифа остаётся без изменений.</p><p>В антикафе постоянно действует акция для именинников: в день рождения или в период 5 дней до и 5 дней после него можно получить одно бесплатное посещение по «Чайному» тарифу. Чтобы воспользоваться предложением, нужно заранее предъявить паспорт.</p><div class="contentSlider post-big-preview-slider swiper-container"><div class="swiper-wrapper"><div class="contentSliderList-item post-big-preview-slide swiper-slide"><img alt="" class="contentImage-image contentImage-slider-image post-preview-image post-big-preview-image swiper-lazy" data-full="//media.kudago.com/images/rich_editor/85/b6/85b609457d50f8f0370224e722a79c4b.jpg" src="//media.kudago.com/thumbs/xl/images/rich_editor/85/b6/85b609457d50f8f0370224e722a79c4b.jpg"/></div><div class="contentSliderList-item post-big-preview-slide swiper-slide"><img alt="" class="contentImage-image contentImage-slider-image post-preview-image post-big-preview-image swiper-lazy" data-full="//media.kudago.com/images/rich_editor/67/54/6754e22f7fdec40bbe840c276e351906.jpg" src="//media.kudago.com/thumbs/xl/images/rich_editor/67/54/6754e22f7fdec40bbe840c276e351906.jpg"/></div><div class="contentSliderList-item post-big-preview-slide swiper-slide"><img alt="" class="contentImage-image contentImage-slider-image post-preview-image post-big-preview-image swiper-lazy" data-full="//media.kudago.com/images/rich_editor/8d/33/8d33f72cc492aa40438039eb55fd6a48.jpg" src="//media.kudago.com/thumbs/xl/images/rich_editor/8d/33/8d33f72cc492aa40438039eb55fd6a48.jpg"/></div><div class="contentSliderList-item post-big-preview-slide swiper-slide"><img alt="" class="contentImage-image contentImage-slider-image post-preview-image post-big-preview-image swiper-lazy" data-full="//media.kudago.com/images/rich_editor/2d/aa/2daaebb10eaa69b13c7cb1880278c187.jpg" src="//media.kudago.com/thumbs/xl/images/rich_editor/2d/aa/2daaebb10eaa69b13c7cb1880278c187.jpg"/></div><div class="contentSliderList-item post-big-preview-slide swiper-slide"><img alt="" class="contentImage-image contentImage-slider-image post-preview-image post-big-preview-image swiper-lazy" data-full="//media.kudago.com/images/rich_editor/83/6f/836fc1144cb2df2b8bf46bc6e0e2ec04.jpg" src="//media.kudago.com/thumbs/xl/images/rich_editor/83/6f/836fc1144cb2df2b8bf46bc6e0e2ec04.jpg"/></div><div class="contentSliderList-item post-big-preview-slide swiper-slide"><img alt="" class="contentImage-image contentImage-slider-image post-preview-image post-big-preview-image swiper-lazy" data-full="//media.kudago.com/images/rich_editor/c7/20/c7209345988d1fec735ecf58a32e409f.jpg" src="//media.kudago.com/thumbs/xl/images/rich_editor/c7/20/c7209345988d1fec735ecf58a32e409f.jpg"/></div><div class="contentSliderList-item post-big-preview-slide swiper-slide"><img alt="" class="contentImage-image contentImage-slider-image post-preview-image post-big-preview-image swiper-lazy" data-full="//media.kudago.com/images/rich_editor/73/2f/732fda3fab68f152eb006d5e446a1c26.jpg" src="//media.kudago.com/thumbs/xl/images/rich_editor/73/2f/732fda3fab68f152eb006d5e446a1c26.jpg"/></div><div class="contentSliderList-item post-big-preview-slide swiper-slide"><img alt="" class="contentImage-image contentImage-slider-image post-preview-image post-big-preview-image swiper-lazy" data-full="//media.kudago.com/images/rich_editor/7c/80/7c80b0cc58b10eef2e383425e8cc6804.jpg" src="//media.kudago.com/thumbs/xl/images/rich_editor/7c/80/7c80b0cc58b10eef2e383425e8cc6804.jpg"/></div><div class="contentSliderList-item post-big-preview-slide swiper-slide"><img alt="" class="contentImage-image contentImage-slider-image post-preview-image post-big-preview-image swiper-lazy" data-full="//media.kudago.com/images/rich_editor/a9/a1/a9a1c68cd6589688eeadf1f093e6d837.jpg" src="//media.kudago.com/thumbs/xl/images/rich_editor/a9/a1/a9a1c68cd6589688eeadf1f093e6d837.jpg"/></div><div class="contentSliderList-item post-big-preview-slide swiper-slide"><img alt="" class="contentImage-image contentImage-slider-image post-preview-image post-big-preview-image swiper-lazy" data-full="//media.kudago.com/images/rich_editor/54/2a/542a8ea304c86dc1003636ed3abf8661.jpg" src="//media.kudago.com/thumbs/xl/images/rich_editor/54/2a/542a8ea304c86dc1003636ed3abf8661.jpg"/></div></div><div class="contentSlider-pagination post-preview-pagination"></div><div class="contentSlider-navigation"><div class="swiper-button-prev"></div><div class="swiper-button-next"></div></div><div class="swiper-button-fullscreen"></div></div><p><em>* Подробности акций, порядок и сроки их проведения уточняйте у организаторов.</em></p>	https://vk.com/12rooms	{"lat": 59.9340383000001, "lon": 30.32947859999992}	["Гостиный двор, Невский Проспект"]	f	[{"url": "https://media.kudago.com/images/place/87/12/87121c7935e743fdbafc9176f872ca5a.jpg", "source": "kudago", "is_main": true}, {"url": "https://media.kudago.com/images/place/03/8a/038acfbc682508caa595b679e1d54297.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/96/f9/96f9e26446a8e7def38b04475a9e38af.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/64/48/6448f1579f8353a716e7e9751ad48c40.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/8b/30/8b30a6a61bb16c0059cab2a532a62325.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/de/1e/de1e0fe610c41b9566e4c08f08317e5e.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/48/24/4824e11e3292768366bd3b3a4eaef9ff.jpg", "source": "kudago", "is_main": false}, {"url": "https://media.kudago.com/images/place/e5/6e/e56e6eb9294db080fa227e128718f4cd.jpg", "source": "kudago", "is_main": false}]	https://media.kudago.com/images/place/87/12/87121c7935e743fdbafc9176f872ca5a.jpg	2025-10-20 19:19:04.911	